// n4_14 — ReLU6 (relu + requantize) for [1,192,14,14], flat-bus
// scale_factor = 2.762976964314779, clip_max = 6
// SCALE_MULT/SCALE_SHIFT chosen with MULT in [1,32767]:
//   SHIFT=12, MULT=11317  ->  11317/4096 = 2.76293945... (err ~ 1.36e-5)
module n4_14 (
    input  wire            clk,
    input  wire            rst_n,
    input  wire            valid_in,
    output reg             ready_in,
    input  wire [1535:0]   data_in,
    output reg             valid_out,
    output reg  [1535:0]   data_out
);

    localparam integer OC          = 192;
    localparam integer SCALE_MULT  = 11317;
    localparam integer SCALE_SHIFT = 12;
    localparam integer SCALED_W    = 32;

    localparam signed [SCALED_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    integer i;
    reg signed [7:0]           in_byte;
    reg signed [7:0]           relu_byte;
    reg signed [SCALED_W-1:0]  scaled;
    reg signed [SCALED_W-1:0]  rounded;
    reg signed [SCALED_W-1:0]  clamped;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            valid_out <= 1'b0;
            ready_in  <= 1'b1;  // [INVARIANT:READY_IN_GATING]
            data_out  <= 1536'b0;
        end else begin
            ready_in  <= 1'b1;  // [INVARIANT:READY_IN_GATING]
            valid_out <= valid_in;  // [INVARIANT:VALID_OUT_LATENCY]
            if (valid_in) begin
                for (i = 0; i < OC; i = i + 1) begin
                    in_byte   = $signed(data_in[i*8 +: 8]);
                    relu_byte = (in_byte > 8'sd0) ? in_byte : 8'sd0;
                    scaled    = relu_byte * SCALE_MULT_CONST;
                    // [INVARIANT:ROUNDING]
                    rounded   = (scaled +
                                 (scaled[SCALED_W-1] ? SCALE_ROUND_HALF_M1
                                                     : SCALE_ROUND_HALF)
                                ) >>> SCALE_SHIFT;
                    clamped   = (rounded >  32'sd127) ?  32'sd127 :
                                (rounded < -32'sd128) ? -32'sd128 : rounded;
                    data_out[i*8 +: 8] <= clamped[7:0];
                end
            end
        end
    end

endmodule
